package org.eclipse.rdf4j.sail.base;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.reflect.Method;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Or;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorAccessShapeTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI GRID_NAME = VF.createIRI("urn:grid:name");
	private static final IRI GRID_ALIAS = VF.createIRI("urn:grid:alias");

	@Test
	void accessShapeMarksBoundVarEqualityAsLookupUsable() {
		SketchBasedJoinEstimator estimator = estimatorWithGridLiterals();
		Filter filteredName = new Filter(pattern("substation", GRID_NAME, "name"),
				equality("name", Var.of("target")));

		SketchBasedJoinEstimator.AccessShape accessShape = estimator
				.accessShapeForJoinOrdering(filteredName, Set.of("target"));

		assertEquals(Set.of(SketchBasedJoinEstimator.Component.O), accessShape.filterLookupComponents());
		assertTrue(accessShape.lookupBoundComponents().contains(SketchBasedJoinEstimator.Component.P));
		assertTrue(accessShape.lookupBoundComponents().contains(SketchBasedJoinEstimator.Component.O));
		assertFalse(accessShape.isDirectLookup(Set.of(SketchBasedJoinEstimator.Component.O)));
		assertTrue(accessShape.isDirectLookup(Set.of(SketchBasedJoinEstimator.Component.P,
				SketchBasedJoinEstimator.Component.O)));
	}

	@Test
	void accessShapeTreatsSameVarDisjunctionAsFiniteLookupSet() {
		SketchBasedJoinEstimator estimator = estimatorWithGridLiterals();
		Filter singleEquality = new Filter(pattern("substation", GRID_NAME, "name"),
				equality("name", Var.of("target")));
		Filter disjunctiveEquality = new Filter(pattern("substation", GRID_NAME, "name"),
				new Or(equality("name", Var.of("target")),
						equality("name", new ValueConstant(VF.createLiteral("Substation 3")))));

		SketchBasedJoinEstimator.AccessShape singleShape = estimator
				.accessShapeForJoinOrdering(singleEquality, Set.of("target"));
		SketchBasedJoinEstimator.AccessShape disjunctiveShape = estimator
				.accessShapeForJoinOrdering(disjunctiveEquality, Set.of("target"));

		assertEquals(Set.of(SketchBasedJoinEstimator.Component.O), disjunctiveShape.filterLookupComponents());
		assertTrue(disjunctiveShape.filterMultiplier() > singleShape.filterMultiplier(),
				"Finite OR lookup should be treated as more permissive than a single equality");
		assertTrue(disjunctiveShape.filterMultiplier() > 0.0d && disjunctiveShape.filterMultiplier() < 1.0d);
	}

	@Test
	void accessShapeKeepsObjectOnlyScanWiderThanFilteredOutput() {
		SketchBasedJoinEstimator estimator = estimatorWithGridLiterals();
		Filter filteredName = new Filter(pattern("substation", GRID_NAME, "name"),
				new Or(equality("name", Var.of("target")),
						equality("name", new ValueConstant(VF.createLiteral("Substation 3")))));

		SketchBasedJoinEstimator.AccessShape accessShape = estimator
				.accessShapeForJoinOrdering(filteredName, Set.of("target"));
		double objectOnlyScan = accessShape.estimateAccessRows(Set.of(SketchBasedJoinEstimator.Component.O));
		double predicateQualifiedAccess = accessShape.estimateAccessRows(Set.of(SketchBasedJoinEstimator.Component.P,
				SketchBasedJoinEstimator.Component.O));
		double filteredOutputRows = estimateTupleExprPlan(estimator, filteredName, Set.of("target")).outputRows();

		assertTrue(objectOnlyScan > predicateQualifiedAccess,
				"Missing a predicate-qualified prefix should keep the scan broader than the best prefix-qualified access");
		assertTrue(objectOnlyScan > filteredOutputRows,
				"Object-only scan work should stay wider than the filtered output rows");
	}

	private static SketchBasedJoinEstimator estimatorWithGridLiterals() {
		StubSailStore store = new StubSailStore();
		for (int i = 0; i < 24; i++) {
			Resource substation = VF.createIRI("urn:substation:" + i);
			store.add(VF.createStatement(substation, GRID_NAME, VF.createLiteral("Substation " + i)));
		}
		for (int i = 0; i < 120; i++) {
			Resource aliasHolder = VF.createIRI("urn:alias:" + i);
			store.add(VF.createStatement(aliasHolder, GRID_ALIAS, VF.createLiteral("Substation " + (1 + (i % 3)))));
		}

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuildOnceSlow();
		return estimator;
	}

	private static Compare equality(String patternVar, org.eclipse.rdf4j.query.algebra.ValueExpr lookupExpr) {
		return new Compare(Var.of(patternVar), lookupExpr, Compare.CompareOp.EQ);
	}

	private static StatementPattern pattern(String subjVar, IRI pred, String objVar) {
		return new StatementPattern(Var.of(subjVar), Var.of("p", pred), Var.of(objVar));
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static SketchBasedJoinEstimator.TuplePlanEstimate estimateTupleExprPlan(SketchBasedJoinEstimator estimator,
			Filter filter, Set<String> initiallyBoundVars) {
		try {
			Method method = SketchBasedJoinEstimator.class.getDeclaredMethod("estimateTupleExprPlan",
					org.eclipse.rdf4j.query.algebra.TupleExpr.class, Set.class);
			method.setAccessible(true);
			return (SketchBasedJoinEstimator.TuplePlanEstimate) method.invoke(estimator, filter, initiallyBoundVars);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}
}
